parameters.jsCode:
const options = [];
  const mapping = {};

  // Add "Create new company" as first option
  options.push({ option: "➕ Create new company" });
  mapping["➕ Create new company"] = "NEW";

  for (const item of $input.all()) {
    options.push({ option: item.json.name });
    mapping[item.json.name] = item.json.key;
  }

  const select = {
    fieldLabel: "client",
    fieldType: "dropdown",
    fieldOptions: { values: options },
    requiredField: true
  };

  return { select, mapping };

const formData = $('On form submission').first().json;  // adjust node name if needed
let companyName = $input.first().json.client ?? $input.first().json['Company Name'];
companyName = companyName.toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '');
  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZabcdefghjkmnpqrstuvwxyz23456789!@#$%';
  let password = '';
  for (let i = 0; i < 16; i++) {
    password += chars.charAt(Math.floor(Math.random() * chars.length));
  }

  return [{
    json: {
      ...formData,
      password,
      companyName
    }
  }];

const companyName = $('Form').first().json['Company Name'];
  const clientKey = companyName
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '');

  return [{
    json: {
      ...$json,
      client_key: clientKey,
      domain: $('Form').first().json.Domain
    }
  }];

